+    #[test]
+    fn origin_session_cancel_flow() {
+        let cx: Cx = Cx::for_testing();
+        let rtid = RemoteTaskId::next();
+        let origin = OriginSession::<OriginInit>::new(rtid);
+        let req = test_spawn_request(&cx, rtid);
+        let origin = origin.send_spawn(&req).unwrap();
